/**
 * useBackupOnboarding Hook
 *
 * Manages onboarding modal state
 * - Check if user has backup folder configured
 * - Check reminder preference (every session / 7 days / never)
 * - Calculate if modal should show
 * - Track first content creation
 */

import { useEffect, useState } from 'react';
import { useThemeStore } from '../stores/useThemeStore';

export function useBackupOnboarding() {
  const backupPreferences = useThemeStore((state) => state.backupPreferences);
  const [shouldShowModal, setShouldShowModal] = useState(false);

  // Use sessionStorage to persist hasChecked across page reloads within the same session
  const [hasChecked, setHasChecked] = useState(() => {
    return sessionStorage.getItem('backup-modal-checked') === 'true';
  });

  useEffect(() => {
    // Only check once per session (persists across page navigations)
    if (hasChecked) return;

    const checkShouldShow = () => {
      // Don't show if user already has backup configured
      if (backupPreferences.hasBackupFolder) {
        markAsChecked();
        return false;
      }

      // Check reminder preference
      const { reminderPreference, nextReminderDate } = backupPreferences;

      // Never show again
      if (reminderPreference === 'never') {
        markAsChecked();
        return false;
      }

      // Show every session
      if (reminderPreference === 'every-session') {
        markAsChecked();
        return true;
      }

      // Show in 7 days - check if date has passed
      if (reminderPreference === 'in-7-days' && nextReminderDate) {
        const now = new Date();
        const reminderDate = new Date(nextReminderDate);

        if (now >= reminderDate) {
          markAsChecked();
          return true;
        }
      }

      markAsChecked();
      return false;
    };

    const shouldShow = checkShouldShow();
    setShouldShowModal(shouldShow);
  }, [backupPreferences, hasChecked]);

  // Helper to mark as checked in both state and sessionStorage
  const markAsChecked = () => {
    sessionStorage.setItem('backup-modal-checked', 'true');
    setHasChecked(true);
  };

  return {
    shouldShowModal,
    dismissModal: () => setShouldShowModal(false),
  };
}

/**
 * BackupOnboardingModal Component
 *
 * First-time onboarding modal for backup setup
 * - Step 1: Why Backup?
 * - Step 2: Choose Cloud Provider
 * - Step 3: Platform-Specific Instructions
 * - Step 4: Folder Picker (FSA API)
 * - Step 5: Reminder Preferences
 */

import { useState } from 'react';
import { Modal } from './Modal';
import { useThemeStore } from '../stores/useThemeStore';
import { autoSaveManager } from '../services/autoSave';
import { requestAutoSaveDirectory } from '../services/brainBackup';

interface BackupOnboardingModalProps {
  isOpen: boolean;
  onClose: () => void;
}

type CloudProvider = 'icloud' | 'google-drive' | 'onedrive' | 'proton-drive' | 'dropbox' | 'none';
type Platform = 'windows' | 'macos';
type ReminderPreference = 'every-session' | 'in-7-days' | 'never';

export function BackupOnboardingModal({ isOpen, onClose }: BackupOnboardingModalProps) {
  const [currentStep, setCurrentStep] = useState(1);
  const [selectedProvider, setSelectedProvider] = useState<CloudProvider | null>(null);
  const [platform, setPlatform] = useState<Platform>(() => {
    // Detect platform
    const userAgent = navigator.userAgent.toLowerCase();
    return userAgent.includes('mac') ? 'macos' : 'windows';
  });
  const [reminderPreference, setReminderPreference] = useState<ReminderPreference>('every-session');
  const [isSelecting, setIsSelecting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const updateBackupPreferences = useThemeStore((state) => state.updateBackupPreferences);

  const totalSteps = 5;

  /**
   * Handle folder selection (Step 4)
   */
  const handleSelectFolder = async () => {
    setIsSelecting(true);
    setError(null);

    try {
      const dirHandle = await requestAutoSaveDirectory();

      // Update preferences
      updateBackupPreferences({
        hasBackupFolder: true,
        backupFolderPath: dirHandle.name,
        autoSaveEnabled: true,
      });

      // Enable auto-save
      await autoSaveManager.enableLocal(dirHandle);

      // Move to next step
      setCurrentStep(5);
    } catch (err) {
      if ((err as Error).name === 'AbortError') {
        setError('Folder selection cancelled. Please select a folder to continue.');
      } else {
        setError(`Error: ${(err as Error).message}`);
      }
    } finally {
      setIsSelecting(false);
    }
  };

  /**
   * Handle reminder preference save (Step 5)
   */
  const handleSaveReminder = () => {
    const nextReminderDate =
      reminderPreference === 'in-7-days'
        ? new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString()
        : null;

    updateBackupPreferences({
      reminderPreference,
      nextReminderDate,
    });

    onClose();
  };

  /**
   * Cloud provider instructions
   */
  const getInstructions = (provider: CloudProvider, platform: Platform) => {
    const instructions: Record<CloudProvider, Record<Platform, { title: string; steps: string[] }>> = {
      icloud: {
        windows: {
          title: 'iCloud Drive (Windows)',
          steps: [
            'Install iCloud for Windows from the Microsoft Store',
            'Sign in with your Apple ID',
            'Enable "iCloud Drive" in iCloud settings',
            'Open File Explorer and navigate to iCloud Drive',
            'Create a folder named "Neuman Brain Backups" (or any name you prefer)',
            'In the next step, select this folder when prompted',
          ],
        },
        macos: {
          title: 'iCloud Drive (macOS)',
          steps: [
            'Open System Settings → Apple ID → iCloud',
            'Enable "iCloud Drive"',
            'Open Finder and navigate to iCloud Drive (in sidebar)',
            'Create a folder named "Neuman Brain Backups" (or any name you prefer)',
            'In the next step, select this folder when prompted',
          ],
        },
      },
